import React, { useEffect } from 'react'
import Room from './Room';

export default function ShowRooms(props) {

    let showRooms=()=>{
    props.rooms.map((r) => { return <Room name={r.name} type={r.roomType} color={r.roomColor}/> })}

  

  return (
    <div> {showRooms()}</div>
  )
}
